package main

import (
	"bytes"
	"compress/zlib"
	"encoding/hex"
	"fmt"
	"io"
	"math/rand"
	"time"
)

func main() {
	// ここに16進数データを並べていく（今はアリスだけ）
	dataList := []string{
		"",
	}

	rand.Seed(time.Now().UnixNano())
	target := dataList[rand.Intn(len(dataList))]

	data, _ := hex.DecodeString(target)
	b := bytes.NewReader(data)
	r, _ := zlib.NewReader(b)
	var out bytes.Buffer
	io.Copy(&out, r)
	r.Close()

	// AAを表示
	fmt.Println(out.String())

	// 画面を止め、終了を促すメッセージ
	fmt.Println("\n------------------------------------")
	fmt.Println("Enterキーを押すと終了します...")
	fmt.Scanln()
}
